VALUES
  ('optometrist-moex-00404', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '對於斜視的矯正，何者為較不好的預後因子？', '["共同性斜視（comitantstrabismus）", "雙眼視力良好", "偏心注視（eccentricfixation）", "正常網膜對應（normalcorrespondence）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00405', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '3歲半內斜視兒童，散瞳後驗光所得為右眼+3.50D與左眼+3.50D。在沒有散瞳劑的情況下用檢影鏡檢查 發現雙眼度數都為+3.25D。假設患者調節性內聚力/調節力比值（AC/Aratio）無異常，關於他的配鏡，下 列何者最為適當？', '["兒童遠視一般不需要全矯正，可以建議他配度數輕一點", "這位病患的內斜視，配戴遠視全矯正眼鏡之後有可能變好", "這位病患配戴雙焦點眼鏡比較好", "這位病患配戴漸進式多焦點眼鏡比較好"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00406', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關弱視（amblyopia）的敘述，下列何者錯誤？', '["常因為早年發生視覺刺激不足所導致的明顯視力低下無法矯正", "視覺剝奪（visualdeprivation）的情況越嚴重，會造成弱視患者矯正視力越差", "部分斜視患者為了避免弱視，會發展出間歇性斜視（intermittentheterotropia）", "雙眼不等視（anisometropia）患者若是在屈光不正度數允許下，可能會發展出一隻眼睛專門看近，另一 隻專門看遠的情況，以避免弱視發生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00407', 'optometrist', 'optometrist-moex-113-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '下列關於水晶體的敘述何者錯誤？', '["隨著老化其中心厚度增加，曲率半徑（radius）變長", "為雙凸構造，前表面的曲率半徑約為後表面的1.7倍", "中心核的折射率比周圍皮質大", "位於水晶體後面的是玻璃體，其折射率可視為與前房相同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "68f98e0b0869", "answer_pdf_sha1": "6cdd7d434734", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00408', 'optometrist', 'optometrist-moex-113-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '一物體置於薄透鏡前18cm處，成像位於透鏡前6cm處，此透鏡的焦距為何？', '["-3cm", "-6cm", "-9cm", "-12cm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "68f98e0b0869", "answer_pdf_sha1": "6cdd7d434734", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00409', 'optometrist', 'optometrist-moex-113-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '假設一患者為順性散光，且散光全來自眼角膜，下列敘述何者錯誤？', '["散光的兩個子午面相差90度", "-2.00DS/+1.00DC 90有可能是此病患的眼鏡", "物體經此眼睛折射後，水平的焦線一定於視網膜前，垂直的焦線一定位於視網膜後 ×", "眼角膜在水平向較為平坦"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "68f98e0b0869", "answer_pdf_sha1": "6cdd7d434734", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00410', 'optometrist', 'optometrist-moex-113-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '若將眼球視為單一屈光表面，眼球內折射率為 1.333，根據眼成像關係，下列何組眼軸長與屈光力之搭配 非正視眼？', '["22.98mm、+58.0DS", "22.22mm、+60.0DS", "21.67mm、61.5DS", "21.02mm、62.5DS"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "68f98e0b0869", "answer_pdf_sha1": "6cdd7d434734", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00411', 'optometrist', 'optometrist-moex-113-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '關於戴眼鏡或隱形眼鏡影像的放大率，下列敘述何者錯誤？', '["軸性近視（axialmyopia）的人較適合戴眼鏡矯正，看東西的大小和正視眼的人相比，大小比較不會改變", "屈光性遠視（refractivehyperopia）的人較適合戴眼鏡矯正，看東西的大小和正視眼的人相比，大小比較 不會改變", "軸性遠視（axialhyperopia）的人戴隱形眼鏡矯正，看東西的大小會比正視眼的人看東西，看起來較小", "屈光性近視（refractivemyopia）的人戴眼鏡矯正，看東西的大小會比正視眼的人看東西，看起來較小"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "68f98e0b0869", "answer_pdf_sha1": "6cdd7d434734", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00412', 'optometrist', 'optometrist-moex-113-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', 'CR39鏡片黃光折射率為1.5、藍光折射率為1.50460、紅光折射率為1.49598，鏡片屈光度為+10.00D，於 鏡片中心上方1.2mm處產生之橫向色像差（lateralchromaticaberration）為何？', '["2稜鏡度", "1.2稜鏡度", "0.2稜鏡度", "0.02稜鏡度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "68f98e0b0869", "answer_pdf_sha1": "6cdd7d434734", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
